  constructor(props) {
    super(props);
    this.handlePageChange = this.handlePageChange.bind(this);
    this.retrieveData = this.retrieveData.bind(this);
    this.showhidemap = this.showhidemap.bind(this);

    this.state = {
      contacts: [],
      isLoading: false,
      loction: "",
      lat: 0,
      lng: 0,
      service_categories: [],
      currentIndex: -1,
      page: 1,
      distance: "",
      count: 0,
      pageSize: 9,
      years: [],
      keyword: "",
      restofworld: true,
      totalItemsString: [],
      brands: [],
      totalPages: 0,
      showmap: false,
      isForReviewToggle: false,
      selectedContactId: "",
      selectedUserId: "",
      isForViewToggle: false,
      titleValue: "",
      reviewValue: "",
      isRecommended: false,
      isChecked: false,
      rating: 0,
      reviewRating: {
        customerService: 0,
        buyingService: 0,
        overallService: 0,
      },
      is_login: 0,
    };

    const url = "/contacts.php?action=get_load_data";

    http
      .get(url)
      .then(response => response.data)
      .then(data => {
        this.setState({ is_login: data.login });
      });
  }

  handleRating = (value, name) => {
    switch (name) {
      case "customer":
        this.setState({
          reviewRating: {
            ...this.state.reviewRating,
            customerService: value,
          },
        });
        break;
      case "buying":
        this.setState({
          reviewRating: {
            ...this.state.reviewRating,
            buyingService: value,
          },
        });
        break;
      case "overall":
        this.setState({
          reviewRating: {
            ...this.state.reviewRating,
            overallService: value,
          },
        });
        break;
      default:
        break;
    }
  };

  handleSubmit = () => {
    const url = "/contacts.php?action=set_dealer_rating";

    let params = {};
    params["dealer_id"] = this.state.selectedUserId;
    params["post_content"] = this.state.reviewValue;
    params["post_title"] = this.state.titleValue;
    params["rate_1"] = this.state.reviewRating.customerService;
    params["rate_2"] = this.state.reviewRating.buyingService;
    params["rate_3"] = this.state.reviewRating.overallService;
    params["stm_recommended"] = this.state.isRecommended ? "yes" : "no";

    http
      .get(url, { params })
      .then(response => response.data)
      .then(data => {
        window.alert("Review Added");
      })
      .catch(() => {
        window.alert("Something went wrong");
      });

    this.setState({
      reviewRating: {
        customerService: 0,
        buyingService: 0,
        overallService: 0,
      },
      isForReviewToggle: false,
      isChecked: false,
      isRecommended: false,
      titleValue: "",
      reviewValue: "",
    });
  };

  showhidemap = childName => {
    this.setState(
      {
        showmap: !this.state.showmap,
      },
      () => {},
    );
    //this.retrieveData();
  };
  handlebrandCallback = childName => {
    this.setState(
      {
        brands: childName,
      },
      () => {
        this.retrieveData();
      },
    );
    //this.retrieveData();
  };

  handleCallback = childName => {
    this.setState(
      {
        service_categories: childName,
      },
      () => {
        this.retrieveData();
      },
    );
    //this.retrieveData();
  };

  handleCallbackyear = childName => {
    this.setState(
      {
        years: childName,
      },
      () => {
        this.retrieveData();
      },
    );
    //this.retrieveData();
  };
  handleUserFav = event => {
    //alert(event.target.dataset.id);
    const url = "/contacts.php?action=update_user_fav";

    let params = { user_id: event.currentTarget.dataset.id };

    http
      .get(url, { params })
      .then(response => response.data)
      .then(data => {
        // event.target.innerHTML = data.data;
        alert(data.data);
        // console.log(data.data);
      });
  };

  handlekeywordsSearch = event => {
    this.setState(
      {
        keyword: event.target.value,
      },
      () => {
        this.retrieveData();
      },
    );
  };
  handleDistanceChange = event => {
    this.setState(
      {
        distance: event.target.value,
      },
      () => {
        this.retrieveData();
      },
    );
  };
  handleClick() {
    console.log("Button clicked!");
  }

  handleRemoveRegion = event => {
    const { restofworld } = this.state;
    this.setState(
      {
        restofworld: !restofworld,
      },
      () => {
        this.retrieveData();
      },
    );
  };

  handlePageChange(event, value) {
    this.setState(
      {
        page: value,
      },
      () => {
        this.retrieveData();
      },
    );
  }
  retrieveData() {
    const url = "/contacts.php?action=getprovider";
    const {
      page,
      service_categories,
      years,
      distance,
      lat,
      lng,
      loction,
      keyword,
      restofworld,
      brands,
    } = this.state;
    this.setState({ isLoading: true });
    let params = {};
    params["page"] = page - 1;
    params["service_categories"] = service_categories;
    params["brands"] = brands;
    params["distance"] = distance;
    params["lat"] = lat;
    params["lng"] = lng;
    params["loction"] = loction;
    params["keyword"] = keyword;
    params["restofworld"] = restofworld;
    // const shuffle = arr => [...arr].sort(() => Math.random() - 0.5);

    http
      .get(url, { params })
      .then(response => response.data)
      .then(data => {
        this.setState({
          contacts: data.products,
          count: data.totalItems,
          totalPages: data.totalPages,
          totalItemsString: data.totalItemsString,
        });
        //   console.log(data);
        window.scrollTo({ top: 0 });
        this.setState({ isLoading: false });
      });
  }

  componentDidMount() {
    this.retrieveData();
  }

  viewSection = (productId, userId) => {
    this.setState({
      selectedContactId: productId,
      isForViewToggle:
        this.state.selectedContactId != productId
          ? true
          : !this.state.isForViewToggle,
      isForReviewToggle: false,
    });
  };
  reviewSection = (productId, userId) => {
    if (this.state.is_login == 0) {
      window.alert("Please login to Write a Review");
    } else {
      this.setState({
        selectedContactId: productId,
        selectedUserId: userId,
        isForReviewToggle:
          this.state.selectedContactId != productId
            ? true
            : !this.state.isForReviewToggle,
        isForViewToggle: false,
        isChecked: false,
        isRecommended: false,
        titleValue: "",
        reviewValue: "",
        reviewRating: {
          customerService: 0,
          buyingService: 0,
          overallService: 0,
        },
      });
    }
  };

  handleChange = e => {
    this.setState(prevState => ({
      ...prevState,
      [e.target.name]:
        e.target.name == "isChecked"
          ? e.target.checked
          : e.target.name == "isRecommended"
          ? e.target.value == "yes"
            ? true
            : false
          : e.target.value,
    }));
  };
