import React, { useState } from 'react';
import Button from 'react-bootstrap/Button';
import Modal from 'react-bootstrap/Modal';

export default function ModelPopup(props) {
  const [show, setShow] = useState(false);

  const handleClose = () => setShow(false);
  const handleShow = () => setShow(true);

  return (
    <>
      <a href="#" variant="primary" className="tagboxservice Offers_tag" onClick={handleShow}>
        Special Offer
      </a>

      <Modal show={show} onHide={handleClose}>
        <Modal.Header closeButton>
          <Modal.Title className="h2">{props.title}</Modal.Title>
        </Modal.Header>
        <Modal.Body className="offer_popup_boday">{props.children}</Modal.Body>
        <Modal.Footer>
        <div style={{ float: "left", textAlign: "left", display: "block" }}> Valid Untill: {props.offer_end_date}</div>
<a href={props.link_to_offer}>Click here for more details</a>
          <Button variant="secondary" onClick={handleClose}>
            Close
          </Button>
          
        </Modal.Footer>
      </Modal>
    </>
  );
}
