import React, { Component } from "react";
import { BrowserRouter as Router, Routes, Route, Link } from "react-router-dom";
import 'bootstrap/dist/css/bootstrap.min.css';
import ProviderList from "./components/provider-list.component";
import Header from "./components/header"
import Footer from "./components/footer"
import http from "./http-common";


import "./App.css";

//import AddTutorial from "./components/add-tutorial.component";
//import Tutorial from "./components/tutorial.component";
//import TutorialsList from "./components/products-list.component";

class App extends Component {
  


constructor(props) {
    super(props);
    
    this.retrieveData = this.retrieveData.bind(this);
    this.state = {
      is_login : '0',

    }
  }
  retrieveData() {
    const url = "/contacts.php?action=get_load_data";
    const { is_login} = this.state;

    let params = {};
    
    http
      .get(url, { params })
      .then((response) => response.data)
      .then((data) => {
        //this.setState({ is_login: data.login });
        this.setState({ is_login: data.login });
      });
  }



  componentDidMount() {
    this.retrieveData();
  }


  render() {
    
    return (
      <div id="wrapper">
        <Header is_login={this.state.is_login}/>
        <ProviderList/>
        <Footer/>
      </div>
    );
  }
}

export default App;