import React, {useState} from 'react';
import ReactDOM from "react-dom";
import { FaAngleLeft,FaAngleRight } from "react-icons/fa";


import AliceCarousel from 'react-alice-carousel';
import 'react-alice-carousel/lib/alice-carousel.css';
//import "./styles.css";


  // State with list of all checked item
export default function Carousel(props) {   
   
const itemsLength = Array.from({ length: 5 });
const [mainIndex, setMainIndex] = useState(0);

const items = props.items.map((item, index) => {
    const style = { height: 200 + index * 10 };
    return <div className="brandlogo"><img src={item}/></div>;
});

const slideNext = () => {
        if (mainIndex < items.length - 1) {
            
            setMainIndex(mainIndex + 1);
        }else{
            setMainIndex(0);
        }
    };

    const slidePrev = () => {
        if (mainIndex > 0) {
            setMainIndex(mainIndex - 1);
        }else{
            setMainIndex(items.length - 1);
        }

    };


const responsive = {
    0: { items: 3 },
    568: { items: 3 },
    1024: { items: 4 },
};

const Carousel = () => (
<div className="logoCarousel">
<div className="btn-prev" onClick={slidePrev}><FaAngleLeft  style={{fontSize: '13px',color: '#d60f17'}}/></div>
    <AliceCarousel
        activeIndex={mainIndex}
         animationType="fadeout"
         animationDuration={800}
        autoHeight  
        mouseTracking
        items={items}
        paddingLeft={20}
        paddingRight={20}
        disableDotsControls
          responsive={responsive}
          disableButtonsControls
    />
    
           <div className="btn-next" onClick={slideNext}><FaAngleRight  style={{fontSize: '13px',color: '#d60f17'}}/></div>
           </div>
);
return(
  <Carousel/>
  )
}
