import React, {useState, useEffect} from 'react';
import ReactDOM from "react-dom";
import { FaAngleLeft,FaAngleRight } from "react-icons/fa";
import http from "../http-common";

import AliceCarousel from 'react-alice-carousel';
import 'react-alice-carousel/lib/alice-carousel.css';
//import "./styles.css";


  // State with list of all checked item
export default function DisplayAds(props) {   

const [items,setItems] = useState(0);

   

useEffect(() => {
  //  const itemsLength = Array.from({ length: 5 });
//const [mainIndex, setMainIndex] = useState(0);

//const [items,setitems] = useState(0);

const url = '/contacts.php?action=get_ads_data';

     let params = {ads_group: props.ads_group};
     
    http.get(url,{params}).then(response => response.data)
    .then((data) => {
      
      const items1 = data.map((item, index) => {
        const style = { height: 200 + index * 10 };
        return <div className="adsimage"><a href={item.link} target="_blank"> <img src={item.url}/></a>{item.tracking}</div>;
    });
      setItems(items1);
     })

 },[]);





const responsive = {
    0: { items: 1 },
    568: { items: 1 },
    1024: { items: 1 },
};


const Carousel = () => (
<div className="adsslider">

   {items.length && <AliceCarousel

         autoPlayInterval={20000}
         
        autoHeight  
        mouseTracking
        items={items}
        autoPlay={true}
        infinite={true}

        disableDotsControls
          responsive={responsive}
          disableButtonsControls
    />
}
    
           
           </div>
);

return(
  <Carousel/>
  )
}
